+    fn announce_accessible(&mut self, message: impl Into<String>) {
+        if !self.accessible {
+            return;
+        }
+        let message = message.into();
+        tracing::info!(target: "a11y.announce", message = %message, "Accessibility announcement");
+        self.set_status(message);
